mapper.select:
select id, item_name, item_desc, cost_balance, stock, per_user_limit, fulfillment_mode, status, create_time, update_time
from reward_item
where id = #{id}

mapper.update:
update reward_item
set stock = stock - 1,
    update_time = current_timestamp
where id = #{id}
  and status = 'ACTIVE'
  and stock > 0
  and (
      per_user_limit <= 0
      or (
          select count(*)
          from reward_order
          where user_id = #{userId}
            and item_id = #{id}
            and status in ('PENDING', 'PROCESSING', 'FULFILLED')
      ) <= per_user_limit
  )
